<file name="f:\AUDIRA-BUG-HUTTER\apps\web\app\dashboard\page.tsx" language="typescriptreact"  truncated="true">
<content>
'use client';

import React, { useState, useEffect, useRef } from 'react';
import { 
  Shield, Terminal as TermIcon, ShieldAlert, Cpu, 
  Layers, Users, Zap, Globe, Search, Play, ArrowRight,
  Sparkles, CheckCircle2, ChevronRight, RefreshCcw, Wifi, AlertTriangle,
  Brain, Network, Code, Lock, Compass, FileText, Database, TrendingUp,
  Heart, Github, Slack, MessageSquare, Check, Plus, Menu, X, ChevronDown,
  Settings, Key, Compass as CompassIcon, BookMarked, Activity, Bell, Send,
  ChevronUp, ZoomIn, ZoomOut, Maximize2, SearchCode, FileSpreadsheet
} from 'lucide-react';
import Link from 'next/link';

export default function Dashboard() {
  // Navigation active tab
  const [activeNav, setActiveNav] = useState('dashboard');

  // Search command palette state
  const [isSearchFocused, setIsSearchFocused] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // Interactive Live Scanning progress states
  const [appProgress, setAppProgress] = useState(89);
  const [apiProgress, setApiProgress] = useState(45);
  const [cmsProgress, setCmsProgress] = useState(23);

  // Shell Terminal State
  const [shellLogs, setShellLogs] = useState<string[]>([
    '[+] Starting full scan on app.example.com',
    '[+] Subdomain enumeration... Found 23 subdomains',
    '[+] Port scanning... Completed',
    '[+] Service detection... Completed',
    '[+] Vulnerability scanning... 89%',
    '[!] SQL Injection found on /login (HIGH)',
    '[+] XSS found on /search (MEDIUM)',
    '[+] Scan completed in 2m 34s',
  ]);
  const [shellInput, setShellInput] = useState('');

  // AI assistant chat state
  const [aiInput, setAiInput] = useState('');
  const [aiChats, setAiChats] = useState<Array<{ role: 'user' | 'assistant'; text: string; time: string; payload?: string; impact?: string[] }>>([
    {
      role: 'user',
      text: 'Explain the SQL Injection vulnerability found on app.example.com/login',
      time: '10:24 AM'
    },
    {
      role: 'assistant',
      text: 'SQL Injection occurs when user input is improperly sanitized in SQL queries. Attackers can manipulate the query to access, modify, or delete database records.',
      time: '10:25 AM',
      payload: `'' OR '1'='1'     -- -`,
      impact: [
        'Bypass authentication',
        'Access sensitive data',
        'Modify or delete database records'
      ]
    }
  ]);

  const terminalEndRef = useRef<HTMLDivElement>(null);

  // Simulate progress bar increments
  useEffect(() => {
    const timer = setInterval(() => {
      setAppProgress(prev => (prev < 100 ? prev + 1 : 89));
      setApiProgress(prev => (prev < 100 ? prev + 2 : 45));
      setCmsProgress(prev => (prev < 100 ? prev + 3 : 23));
    }, 4000);
    return () => clearInterval(timer);
  }, []);

  // Handle Shell Submit
  const handleShellSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!shellInput.trim()) return;

    const input = shellInput.trim().toLowerCase();
    const newLogs = [...shellLogs, `shadow@vulnx:~$ ${shellInput}`];

    if (input.startsWith('scan ')) {
      const target = input.split(' ')[1] || 'target.com';
      newLogs.push(
        `[+] Spawning thread agent targeting ${target}...`,
        `[+] Enumerating open assets and technological profiles...`,
        `[+] Finished. No critical vulnerabilities found on ${target}.`
      );
    } else if (input === 'clear') {
      setShellLogs([]);
      setShellInput('');
      return;
    } else {
      newLogs.push(`shell-cli: unrecognized command. Type 'scan <target>' or 'clear'.`);
    }

    setShellLogs(newLogs);
    setShellInput('');
  };

  // Handle AI Chat Submit
  const handleAiSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!aiInput.trim()) return;

    const userText = aiInput;
    const time = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    setAiChats(prev => [...prev, { role: 'user', text: userText, time }]);
    setAiInput('');

    setTimeout(() => {
      setAiChats(prev => [
        ...prev,
        {
          role: 'assistant',
          text: `I have evaluated your threat request regarding: "${userText}".\n\nEnsure that all inputs are strongly bound utilizing prepared statements and that proper web application firewall (WAF) rule sets are actively configured inside your gateway API models.`,
          time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
        }
      ]);
    }, 1000);
  };

  return (
    <div className="flex h-screen bg-[#050812] text-cyber-text font-sans overflow-hidden select-none scanline">

      {/* 1. LEFT SIDEBAR PANEL */}
      <aside className="w-64 bg-[#080b14] border-r border-white/5 flex flex-col justify-between shrink-0 h-full overflow-y-auto">
        <div className="space-y-6 pt-6">

          {/* Brand Logo */}
          <div className="px-6 flex items-center gap-3">
            <div className="p-2 bg-gradient-to-br from-cyber-green to-cyber-blue border border-black shadow-[2px_2px_0px_0px_rgba(0,0,0,1)] rounded-sm">
              <Shield className="w-5 h-5 text-black" />
            </div>
            <div>
              <span className="font-heading font-extrabold text-base tracking-tight text-white block">
                VULNX <span className="text-cyber-green">HUNTER</span>
              </span>
              <span className="text-[8px] font-mono text-cyber-blue tracking-widest block uppercase font-bold">
                Workspaces Center
              </span>
            </div>
          </div>

          {/* Navigation Links */}
          <nav className="space-y-5 px-3">

            {/* Group 1: Core */}
            <div className="space-y-1">
              <Link 
                href="/dashboard"
                className={`w-full flex items-center justify-between px-3 py-2 rounded-sm text-xs font-heading font-bold uppercase transition-all ${
                  activeNav === 'dashboard'
                    ? 'bg-cyber-green/10 text-cyber-green border border-cyber-green/20'
                    : 'text-cyber-muted hover:text-white hover:bg-white/[0.02]'
                }`}
              >
                <div className="flex items-center gap-2.5">
                  <Layers className="w-4 h-4" />
                  <span>Dashboard</span>
                </div>
              </Link>
            </div>

            {/* Group 2: Recon & Scan */}
            <div className="space-y-1">
              <span className="px-3 text-[9px] font-mono text-white/30 uppercase tracking-widest font-bold block mb-2">
                RECON & SCAN
              </span>
              {[
                { id: 'targets', label: 'Targets', icon: Globe, path: '/targets' },
                { id: 'recon', label: 'Recon Center', icon: CompassIcon, path: '/recon' },
                { id: 'scan', label: 'Scan Center', icon: Zap, path: '/dashboard' },
                { id: 'vuln', label: 'Vulnerability', icon: ShieldAlert, path: '/vulnerability' },
                { id: 'surface', label: 'Attack Surface', icon: Network, path: '/attack-surface' },
                { id: 'reports', label: 'Reports', icon: FileSpreadsheet, path: '/reports' },
                { id: 'terminal', label: 'Live Terminal', icon: TermIcon, path: '/live-terminal' },
              ].map(item => {
                const Icon = item.icon;
                const isActive = activeNav === item.id;
                return (
                  <Link
                    key={item.id}
                    href={item.path}
                    className={`w-full flex items-center gap-2.5 px-3 py-2 rounded-sm text-xs font-heading font-bold uppercase transition-all ${
                      isActive
                        ? 'bg-cyber-green/10 text-cyber-green border border-cyber-green/20'
                        : 'text-cyber-muted hover:text-white hover:bg-white/[0.02]'
                    }`}
                  >
                    <Icon className="w-4 h-4" />
                    <span>{item.label}</span>
                  </Link>
                );
              })}
            </div>

            {/* Group 3: AI Security */}
            <div className="space-y-1">
              <span className="px-3 text-[9px] font-mono text-white/30 uppercase tracking-widest font-bold block mb-2">
                AI SECURITY
              </span>
              {[
                { id: 'ai-assistant', label: 'AI Assistant', icon: Sparkles, badge: 'AI', path: '/ai-assistant' },
                { id: 'payload', label: 'Payload Generator', icon: Code, path: '/payload-generator' },
                { id: 'history', label: 'Payload History', icon: FileText, path: '/payload-history' },
              ].map(item => {
                const Icon = item.icon;
                return (
                  <Link
                    key={item.id}
                    href={item.path}
                    className="w-full flex items-center justify-between px-3 py-2 rounded-sm text-xs font-heading font-bold uppercase text-cyber-muted hover:text-white hover:bg-white/[0.02] transition-colors"
                  >
                    <div className="flex items-center gap-2.5">
                      <Icon className="w-4 h-4" />
                      <span>{item.label}</span>
                    </div>
                    {item.badge && (
                      <span className="text-[8px] font-mono bg-cyber-green text-black font-extrabold px-1 rounded-sm">
                        {item.badge}
                      </span>
                    )}
                  </Link>
                );
              })}
            </div>

            {/* Group 4: Workspace */}
            <div className="space-y-1">
              <span className="px-3 text-[9px] font-mono text-white/30 uppercase tracking-widest font-bold block mb-2">
                WORKSPACE
              </span>
              {[
                { id: 'team', label: 'Team Workspace', icon: Users },
                { id: 'notes', label: 'Notes', icon: FileText },
                { id: 'feed', label: 'Activity Feed', icon: Activity },
                { id: 'bookmarks', label: 'Bookmarks', icon: BookMarked },
              ].map(item => {
                const Icon = item.icon;
                const isActive = activeNav === item.id;
                return (
                  <button
                    key={item.id}
                    onClick={() => setActiveNav(item.id)}
                    className={`w-full flex items-center gap-2.5 px-3 py-2 rounded-sm text-xs font-heading font-bold uppercase transition-all ${
                      isActive
                        ? 'bg-cyber-green/10 text-cyber-green border border-cyber-green/20'
                        : 'text-cyber-muted hover:text-white hover:bg-white/[0.02]'
                    }`}
                  >
                    <Icon className="w-4 h-4" />
                    <span>{item.label}</span>
                  </button>
                );
              })}
            </div>

            {/* Group 5: System */}
            <div className="space-y-1">
              <span className="px-3 text-[9px] font-mono text-white/30 uppercase tracking-widest font-bold block mb-2">
                SYSTEM
              </span>
              {[
                { id: 'settings', label: 'Settings', icon: Settings },
                { id: 'apikeys', label: 'API Keys', icon: Key },
                { id: 'integrations', label: 'Integrations', icon: Compass },
              ].map(item => {
                const Icon = item.icon;
                const isActive = activeNav === item.id;
                return (
                  <button
                    key={item.id}
                    onClick={() => setActiveNav(item.id)}
                    className={`w-full flex items-center gap-2.5 px-3 py-2 rounded-sm text-xs font-heading font-bold uppercase transition-all ${
                      isActive
                        ? 'bg-cyber-green/10 text-cyber-green border border-cyber-green/20'
                        : 'text-cyber-muted hover:text-white hover:bg-white/[0.02]'
                    }`}
                  >
                    <Icon className="w-4 h-4" />
                    <span>{item.label}</span>
                  </button>
                );
              })}
            </div>

          </nav>
        </div>

        {/* Bottom User Card Profile */}
        <div className="p-4 border-t border-white/5 space-y-4">
          <div className="flex items-center gap-3">
            {/* Glowing avatar */}
            <div className="w-10 h-10 rounded-full border border-cyber-green/50 bg-[#050812] flex items-center justify-center relative shadow-[0_0_8px_#00FFB2]">
              <span className="text-lg">👤</span>
              <span className="w-2.5 h-2.5 rounded-full bg-cyber-green border border-[#080b14] absolute bottom-0 right-0 animate-pulse" />
            </div>
            <div className="text-left">
              <span className="text-xs font-heading font-extrabold text-white block">Shadow Hunter</span>
              <span className="text-[9px] font-mono text-cyber-green uppercase font-bold">Premium Plan</span>
            </div>
          </div>

          <div className="space-y-1.5 text-left">
            <div className="flex justify-between text-[8px] font-mono text-cyber-muted font-bold">
              <span>12,450 / 20,000 XP</span>
              <span className="text-white">Level 24</span>
            </div>
            <div className="w-full bg-[#050812] h-1.5 border border-white/5 rounded-full overflow-hidden">
              <div className="bg-cyber-green h-full rounded-full" style={{ width: '62.2%' }} />
            </div>
          </div>
        </div>
      </aside>

      {/* 2. MAIN CONTAINER VIEWPORT */}
      <div className="flex-1 flex flex-col h-full overflow-hidden bg-[#050812]">

        {/* Top Header Search & User Navigation */}
        <header className="h-16 border-b border-white/5 px-6 flex justify-between items-center bg-[#080b14]/50 backdrop-blur-md shrink-0">

          {/* Top Search bar */}
          <div className="relative w-80">
            <Search className="absolute left-3 top-2.5 w-4 h-4 text-cyber-muted" />
            <input 
              type="text" 
              placeholder="Search target, vuln, scan, etc..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              onFocus={() => setIsSearchFocused(true)}
              onBlur={() => setIsSearchFocused(false)}
              className="w-full bg-[#050812] border border-white/10 focus:border-cyber-green outline-none py-1.5 pl-9 pr-14 text-xs font-mono text-white rounded-sm placeholder-cyber-muted/60 transition-all"
            />
            <div className="absolute right-2 top-2 px-1.5 py-0.5 bg-cyber-card border border-white/10 text-[8px] font-mono text-cyber-muted rounded-sm flex items-center gap-0.5 select-none pointer-events-none">
              <span>⌘</span><span>K</span>
            </div>
          </div>

          {/* Action Header Nav */}
          <div className="flex items-center gap-4">

            <button className="p-2 border border-white/5 hover:border-cyber-green bg-[#080b14] text-cyber-muted hover:text-white rounded-sm transition-all relative">
              <Bell className="w-4.5 h-4.5" />
              <span className="w-2 h-2 rounded-full bg-cyber-green absolute top-1 right-1 animate-pulse" />
            </button>

            <button className="p-2 border border-white/5 hover:border-cyber-green bg-[#080b14] text-cyber-muted hover:text-white rounded-sm transition-all">
              <MessageSquare className="w-4.5 h-4.5" />
            </button>

            {/* User detail indicator card */}
            <div className="flex items-center gap-2.5 pl-4 border-l border-white/10">
              <div className="text-right">
                <span className="text-xs font-heading font-extrabold text-white block">Shadow Hunter</span>
                <span className="text-[9px] font-mono text-cyber-muted uppercase block font-bold">Premium Plan</span>
              </div>
              <div className="w-8 h-8 rounded-full border border-white/10 bg-[#080b14] flex items-center justify-center font-bold">
                👤
              </div>
            </div>

          </div>

        </header>

        {/* Scrollable Dashboard Workspace Grid panels */}
        <main className="flex-1 overflow-y-auto p-6 space-y-6">

          {/* Welcome and Workspace trigger buttons */}
          <div className="flex flex-wrap justify-between items-center gap-4 text-left">
            <div>
              <h1 className="font-heading font-bold text-2xl text-white tracking-tight leading-none mb-1.5 flex items-center gap-2">
                Welcome back, Shadow Hunter 👋
              </h1>
              <span className="text-[11px] font-mono text-cyber-green font-bold block uppercase tracking-widest">
                [ The more you know, the more you hack. ]
              </span>
            </div>

            <div className="flex gap-3">
              <button className="neo-btn flex items-center gap-1.5 px-4 py-2 bg-transparent text-cyber-green border border-cyber-green/30 hover:border-cyber-green font-heading font-bold text-xs uppercase tracking-wider rounded-sm transition-all">
                <Zap className="w-3.5 h-3.5 fill-cyber-green" />
                Quick Scan
              </button>
              <button className="neo-btn flex items-center gap-1.5 px-4 py-2 bg-cyber-green text-black border border-black shadow-neo-green font-heading font-bold text-xs uppercase tracking-wider rounded-sm">
                <Plus className="w-3.5 h-3.5" />
                New Target
                <ChevronDown className="w-3.5 h-3.5" />
              </button>
            </div>
          </div>

          {/* ROW 1: CORE STATS CARDS */}
          <div className="grid grid-cols-2 md:grid-cols-5 gap-4">

            {[
              { title: 'Targets', val: '24', change: '+12%', desc: 'Total managed targets', color: 'text-cyber-green', icon: Globe },
              { title: 'Vulnerabilities', val: '342', change: '+18%', desc: 'Total vulnerabilities found', color: 'text-cyber-blue', icon: ShieldAlert },
              { title: 'Critical', val: '27', change: '+25%', desc: 'Critical vulnerabilities', color: 'text-cyber-pink', icon: AlertTriangle },
              { title: 'Scans', val: '128', change: '+8%', desc: 'Total scans executed', color: 'text-cyber-purple', icon: Zap }
            ].map((stat, idx) => {
              const Icon = stat.icon;
              return (
                <div key={idx} className="bg-[#0b1120] border border-white/5 p-4 rounded-sm flex flex-col justify-between min-h-[110px] text-left hover:border-white/10 transition-all relative">
                  <div>
                    <div className="flex justify-between items-center mb-1">
                      <span className="text-[9px] font-mono text-cyber-muted uppercase font-extrabold">{stat.title}</span>
                      <Icon className="w-3.5 h-3.5 text-cyber-muted" />
                    </div>
                    <span className="text-[9px] font-mono text-cyber-muted leading-tight block">{stat.desc}</span>
                  </div>
                  <div className="flex items-baseline gap-2 mt-4">
                    <span className={`text-2xl font-heading font-extrabold tracking-tight ${stat.color}`}>{stat.val}</span>
                    <span className="text-[9px] font-mono text-cyber-green bg-cyber-green/10 px-1 py-0.2 rounded-sm font-bold">{stat.change}</span>
                  </div>
                </div>
              );
            })}

            {/* Custom Radial Progress Security Score Card */}
            <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm flex justify-between items-center min-h-[110px] text-left hover:border-white/10 transition-all">
              <div className="flex flex-col justify-between h-full">
                <div>
                  <span className="text-[9px] font-mono text-cyber-muted uppercase font-extrabold block">Security Score</span>
                  <span className="text-[9px] font-mono text-cyber-muted block leading-tight">Total score rating</span>
                </div>
                <div className="flex items-center gap-1.5 mt-4">
                  <span className="text-xs font-heading font-extrabold text-cyber-green">Good</span>
                  <span className="text-[8px] font-mono text-cyber-green bg-cyber-green/10 px-1 py-0.2 rounded-sm font-bold">+14%</span>
                </div>
              </div>

              {/* Radial Progress Ring SVG */}
              <div className="relative w-16 h-16 flex items-center justify-center shrink-0">
                <svg className="w-full h-full transform -rotate-90">
                  <circle cx="32" cy="32" r="26" stroke="rgba(255,255,255,0.04)" strokeWidth="4.5" fill="transparent" />
                  <circle cx="32" cy="32" r="26" stroke="#00FFB2" strokeWidth="4.5" fill="transparent" strokeDasharray="163.3" strokeDashoffset="35.92" strokeLinecap="round" className="drop-shadow-[0_0_6px_#00FFB2]" />
                </svg>
                <span className="absolute font-heading font-extrabold text-white text-base">78</span>
              </div>
            </div>

          </div>

          {/* ROW 2: ANALYTICS SPLIT (Vulnerability overview vs progress vs top list) */}
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">

            {/* Col 1: Vulnerabilities Donut overview */}
            <div className="lg:col-span-4 bg-[#0b1120] border border-white/5 p-5 rounded-sm text-left">
              <h3 className="text-xs font-heading font-bold text-white uppercase tracking-wider mb-4">Vulnerability Overview</h3>

              <div className="flex justify-between items-center gap-4">

                {/* SVG Donut Chart */}
                <div className="relative w-32 h-32 flex items-center justify-center shrink-0">
                  <svg className="w-full h-full transform -rotate-90">
                    {/* Circle sectors mapping dashboard color ratios */}
                    {/* Total 342 - Critical 27, High 82, Medium 142, Low 64, Info 27 */}
                    {/* Critical (Red) */}
                    <circle cx="64" cy="64" r="48" stroke="#FF3B81" strokeWidth="10" fill="transparent" strokeDasharray="301.6" strokeDashoffset="277.8" strokeLinecap="round" />
                    {/* High (Orange) */}
                    <circle cx="64" cy="64" r="48" stroke="#FF8A00" strokeWidth="10" fill="transparent" strokeDasharray="301.6" strokeDashoffset="205.6" strokeLinecap="round" transform="rotate(28.4 64 64)" />
                    {/* Medium (Yellow) */}
                    <circle cx="64" cy="64" r="48" stroke="#FFD600" strokeWidth="10" fill="transparent" strokeDasharray="301.6" strokeDashoffset="80.6" strokeLinecap="round" transform="rotate(114.7 64 64)" />
                    {/* Low (Blue) */}
                    <circle cx="64" cy="64" r="48" stroke="#00D9FF" strokeWidth="10" fill="transparent" strokeDasharray="301.6" strokeDashoffset="245.2" strokeLinecap="round" transform="rotate(264.3 64 64)" />
                    {/* Info (Purple) */}
                    <circle cx="64" cy="64" r="48" stroke="#7C3AED" strokeWidth="10" fill="transparent" strokeDasharray="301.6" strokeDashoffset="277.8" strokeLinecap="round" transform="rotate(331.8 64 64)" />
                  </svg>
                  <div className="absolute flex flex-col items-center select-none pointer-events-none">
                    <span className="text-xl font-heading font-extrabold text-white">342</span>
                    <span className="text-[8px] font-mono text-cyber-muted uppercase">Total</span>
                  </div>
                </div>

                {/* Donut Legend */}
                <div className="flex-1 space-y-1.5 text-xs font-mono">
                  {[
                    { label: 'Critical', val: '27', pct: '7.9%', color: 'bg-cyber-pink' },
                    { label: 'High', val: '82', pct: '24.0%', color: 'bg-[#FF8A00]' },
                    { label: 'Medium', val: '142', pct: '41.5%', color: 'bg-[#FFD600]' },
                    { label: 'Low', val: '64', pct: '18.7%', color: 'bg-cyber-blue' },
                    { label: 'Info', val: '27', pct: '7.9%', color: 'bg-cyber-purple' }
                  ].map((leg, idx) => (
                    <div key={idx} className="flex justify-between items-center gap-2 text-cyber-muted">
                      <div className="flex items-center gap-1.5 truncate">
                        <span className={`w-2 h-2 rounded-full shrink-0 ${leg.color}`} />
                        <span className="truncate">{leg.label}</span>
                      </div>
                      <div className="flex gap-2 text-right shrink-0">
                        <span className="text-white font-bold">{leg.val}</span>
                        <span className="text-[10px] text-white/40">({leg.pct})</span>
                      </div>
                    </div>
                  ))}
                </div>

              </div>
            </div>

            {/* Col 2: Live Scanning Activity Progress Table */}
            <div className="lg:col-span-5 bg-[#0b1120] border border-white/5 p-5 rounded-sm text-left">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xs font-heading font-bold text-white uppercase tracking-wider">Live Scanning Activity</h3>
                <div className="flex items-center gap-1">
                  <span className="w-2.5 h-2.5 rounded-full bg-cyber-green animate-pulse" />
                  <span className="text-[9px] font-mono text-cyber-green uppercase font-bold">Live</span>
                </div>
              </div>

              <div className="overflow-x-auto">
                <table className="w-full text-xs font-mono">
                  <thead>
                    <tr className="text-white/30 border-b border-white/[0.04] pb-2 text-[9px] uppercase font-bold">
                      <th className="text-left pb-2 font-bold">Target</th>
