<content>
'use client';

import React, { useState, useEffect, useRef } from 'react';
import { 
  Shield, Terminal as TermIcon, ShieldAlert, Cpu, 
  Layers, Users, Zap, Globe, Search, Play, ArrowRight,
  Sparkles, CheckCircle2, ChevronRight, RefreshCcw, Wifi, AlertTriangle,
  Brain, Network, Code, Lock, Compass, FileText, Database, TrendingUp,
  Heart, Github, Slack, MessageSquare, Check, Plus, Menu, X, ChevronDown,
  Settings, Key, Compass as CompassIcon, BookMarked, Activity, Bell, Send,
  ChevronUp, Download, Share2, MoreHorizontal, Calendar, Trash2, SlidersHorizontal,
  Filter, UploadCloud, Info, FileSpreadsheet, Eye, Sparkles as SparkleIcon,
  HelpCircle, ShieldCheck, CheckSquare, Clock, BookOpen, AlertCircle
} from 'lucide-react';
import Link from 'next/link';

// Mock chat messages initial state matching the screenshot exactly
const INITIAL_CHAT_MESSAGES = [
  {
    id: 'msg-1',
    role: 'assistant' as const,
    text: "Hello Shadow Hunter! I'm your AI cybersecurity assistant. \n\nI can help you with:\n• Analyzing vulnerabilities and threats\n• Investigating security incidents\n• Writing and optimizing detection rules\n• Generating reports and summaries\n• Automating security workflows\n• Answering cybersecurity questions\n\nHow can I assist you today?",
    time: '10:24 AM'
  },
  {
    id: 'msg-2',
    role: 'user' as const,
    text: "Analyze the critical vulnerabilities found in example.com and suggest remediation steps.",
    time: '10:31 AM'
  },
  {
    id: 'msg-3',
    role: 'assistant' as const,
    text: "🔍 Analysis Complete\n\nI found 3 critical vulnerabilities in example.com:\n\n1. SQL Injection (Critical) - /login.php\n2. Remote Code Execution (Critical) - /api/upload\n3. Cross-Site Scripting (High) - /search\n\n🛡️ Remediation Steps:\n• Use parameterized queries for SQL Injection\n• Validate and sanitize all file uploads\n• Implement input validation and output encoding\n• Apply Web Application Firewall (WAF) rules\n\nWould you like me to generate a detailed report?",
    time: '10:31 AM',
    isCompleteResponse: true
  }
];

export default function AiAssistantWorkspace() {
  // Navigation active tabs
  const [activeTab, setActiveTab] = useState<'overview' | 'chat' | 'threats' | 'recommendations' | 'automation' | 'playbooks' | 'knowledge' | 'settings'>('overview');
  const [kbTab, setKbTab] = useState<'popular' | 'recent' | 'custom'>('popular');

  // Interactive state variables
  const [chatMessages, setChatMessages] = useState(INITIAL_CHAT_MESSAGES);
  const [chatInput, setChatInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [activeTarget, setActiveTarget] = useState('example.com');
  const [targetExposure, setTargetExposure] = useState(78);

  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Scroll to bottom of chat automatically
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatMessages, isTyping]);

  // Handle send message form submit
  const handleSendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim()) return;

    const userText = chatInput.trim();
    const timeStr = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

    // Add user message
    const userMsg = {
      id: `msg-${Date.now()}-user`,
      role: 'user' as const,
      text: userText,
      time: timeStr
    };
    setChatMessages(prev => [...prev, userMsg]);
    setChatInput('');
    setIsTyping(true);

    // AI dynamic response simulator logic based on user prompt keywords
    setTimeout(() => {
      let aiResponseText = '';
      const query = userText.toLowerCase();

      if (query.includes('sql') || query.includes('injection')) {
        aiResponseText = "🔒 SQL Injection Threat Intelligence Profile:\n\n• Impact: Full database compromise, credential exfiltration, RCE via XP_cmdshell.\n• Payload recommendation: `' UNION SELECT username, password FROM users -- -`.\n• Remediation: Strongly bind input variables, use Prisma parameterized objects, and audit query syntax models.";
      } else if (query.includes('rce') || query.includes('execution')) {
        aiResponseText = "🔥 Remote Code Execution (RCE) Profile:\n\n• Impact: Complete server control, horizontal server lateral movement.\n• Entry point: Unsanitized file uploads inside `/api/upload` allowing `.php` payloads.\n• Mitigation: Store uploads in secure isolated S3 buckets, check file magic numbers, and restrict server write directories.";
      } else if (query.includes('scan') || query.includes('ports')) {
        aiResponseText = "📡 Port scanning diagnostic scheduled. Launched Nmap discovery targeting " + activeTarget + " (TCP ports 1-65535).\n\n• Diagnostic output will stream to Scan Center when completed.";
      } else if (query.includes('waf') || query.includes('firewall')) {
        aiResponseText = "🛡️ Web Application Firewall (WAF) Rule Blueprint:\n\n• Security Policy: Restrict SQL patterns, block custom base64 encoded strings in headers.\n• Action: Block IP addresses sending >= 25 anomalous requests per minute.";
      } else {
        aiResponseText = "💡 Assessor co-pilot query received.\n\nI have logged your request: \"" + userText + "\".\n\nEnsure that all critical parameters on example.com are regularly scanned via active recon threads.";
      }

      const aiMsg = {
        id: `msg-${Date.now()}-ai`,
        role: 'assistant' as const,
        text: aiResponseText,
        time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        isCompleteResponse: true
      };

      setChatMessages(prev => [...prev, aiMsg]);
      setIsTyping(false);
    }, 1500);
