  const [activeSubTab, setActiveSubTab] = useState('All Integrations');
  const [categoryFilter, setCategoryFilter] = useState('All Categories');
  const [statusFilter, setStatusFilter] = useState('All Status');
  const [envFilter, setEnvFilter] = useState('All Environments');
  const [activeDetailTab, setActiveDetailTab] = useState('Overview');

  // Interactive Form Config Edit Hooks
  const [editWorkspace, setEditWorkspace] = useState('');
  const [editChannel, setEditChannel] = useState('');
  const [editEvents, setEditEvents] = useState('');
  const [editUsername, setEditUsername] = useState('');
  const [editIcon, setEditIcon] = useState('');
  const [editWebhookUrl, setEditWebhookUrl] = useState('');
  const [editMute, setEditMute] = useState(false);
  const [editThread, setEditThread] = useState(false);

  // Sync Trigger simulated loader state
  const [syncingId, setSyncingId] = useState<string | null>(null);

  // Select integration
  const selectedInt = useMemo(() => {
    const found = integrations.find(i => i.id === selectedId) || integrations[0];
    // Sync hooks when selection shifts
    return found;
  }, [integrations, selectedId]);

  // Synchronise state values when current integration shifts
  React.useEffect(() => {
    if (selectedInt) {
      setEditWorkspace(selectedInt.config.workspace);
      setEditChannel(selectedInt.config.channel);
      setEditEvents(selectedInt.config.events);
      setEditUsername(selectedInt.config.username);
      setEditIcon(selectedInt.config.iconEmoji);
      setEditWebhookUrl(selectedInt.config.webhookUrl);
      setEditMute(selectedInt.config.muteNotifications);
      setEditThread(selectedInt.config.threadMessages);
    }
  }, [selectedId]);

  // Favorite Star Trigger
  const toggleStar = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setIntegrations(prev => prev.map(item => {
      if (item.id === id) {
        return { ...item, starred: !item.starred };
      }
      return item;
    }));
  };

  // Sync simulated launch
  const triggerSyncSim = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setSyncingId(id);
    setTimeout(() => {
      setSyncingId(null);
      alert(`Integration synchronisation completed successfully. Data logs updated!`);
    }, 2000);
  };

  // Form Save Hooks
  const handleSaveConfig = () => {
    setIntegrations(prev => prev.map(item => {
      if (item.id === selectedId) {
        return {
          ...item,
          config: {
            workspace: editWorkspace,
            channel: editChannel,
            events: editEvents,
            username: editUsername,
            iconEmoji: editIcon,
            webhookUrl: editWebhookUrl,
            muteNotifications: editMute,
            threadMessages: editThread
          }
        };
      }
      return item;
    }));
    alert("Configurations changes saved successfully!");
  };

  // Connect / Disconnect trigger
  const handleToggleConnection = () => {
    setIntegrations(prev => prev.map(item => {
      if (item.id === selectedId) {
        const nextStatus = item.status === 'Connected' ? 'Disconnected' : 'Connected';
        return {
          ...item,
          status: nextStatus,
          lastSync: nextStatus === 'Connected' ? 'Just now' : '-'
        };
      }
      return item;
    }));
  };

  // Delete / Revoke integration
  const handleRevokeIntegration = (id: string, name: string) => {
    if (confirm(`Warning: Are you sure you want to completely revoke and delete the integration with ${name}? All pipelines and logs will be terminated!`)) {
      const filtered = integrations.filter(item => item.id !== id);
      setIntegrations(filtered);
      if (selectedId === id && filtered.length > 0) {
        setSelectedId(filtered[0].id);
      }
    }
  };

  // Create Webhook simulator
  const handleCreateWebhook = () => {
    const name = prompt("Enter Webhook Name (e.g. Slack Incident Channel):");
    const url = prompt("Enter Target URL:") || 'https://hooks.vulnx.com/custom/trigger';
    if (name) {
      setIntegrations(prev => prev.map(item => {
        if (item.id === selectedId) {
          return {
            ...item,
            webhooks: [
              ...item.webhooks,
              { id: `wh-${Date.now()}`, name, url, status: 'Active' }
            ]
          };
        }
        return item;
      }));
      alert("Webhook Endpoint successfully registered!");
    }
  };

  // Connect custom integration
  const handleAddIntegration = () => {
    const name = prompt("Enter Integration Provider Name (e.g. Telegram, OpsGenie):");
    const desc = prompt("Enter Integration Description:");
    const cat = prompt("Enter Category (Communication, SIEM, DevOps, etc.):") || 'Communication';

    if (name) {
      const newInt = {
        id: `i-${Date.now()}`,
        name,
        category: cat,
        description: desc || 'Dynamically integrated service provider',
        status: 'Connected',
        icon: name.toLowerCase(),
        lastSync: 'Just now',
        addedBy: 'Shadow Hunter',
        addedOn: 'May 18, 2024 10:45 AM',
        environment: 'Production',
        lastSyncTime: 'May 18, 2024 10:45 AM',
        starred: false,
        config: {
          workspace: 'default-org',
          channel: '#general',
          events: 'New Vulnerability',
          username: `${name} Agent`,
          iconEmoji: ':zap:',
          webhookUrl: `https://hooks.${name.toLowerCase()}.com/services/trigger`,
          muteNotifications: false,
          threadMessages: false
        },
        syncs: [
          { id: 's-1', time: 'May 18, 2024 10:45 AM', status: 'Success', ago: 'Just now', items: 1 }
        ],
        webhooks: []
      };
      setIntegrations(prev => [newInt, ...prev]);
      setSelectedId(newInt.id);
      alert(`${name} Integration connected successfully!`);
    }
  };

  // Filter integrations
  const filteredIntegrations = useMemo(() => {
    return integrations.filter(item => {
      // 1. Search Query
      if (searchQuery) {
        const query = searchQuery.toLowerCase();
        if (!item.name.toLowerCase().includes(query) && !item.description.toLowerCase().includes(query) && !item.category.toLowerCase().includes(query)) {
          return false;
        }
      }

      // 2. Navigation Tab filter
      if (activeSubTab === 'Connected' && item.status !== 'Connected') return false;
      if (activeSubTab === 'Available' && item.status !== 'Disconnected') return false;
      if (activeSubTab === 'Webhooks' && item.webhooks.length === 0) return false;
      if (activeSubTab === 'Custom Integrations' && item.id.startsWith('wh-')) return false;

      // 3. Dropdowns
      if (categoryFilter !== 'All Categories' && item.category !== categoryFilter) return false;
      if (statusFilter !== 'All Status' && item.status !== statusFilter) return false;
      if (envFilter !== 'All Environments' && item.environment !== envFilter) return false;

      return true;
    });
  }, [integrations, searchQuery, activeSubTab, categoryFilter, statusFilter, envFilter]);

  // Brand Logo Helper
  const renderBrandLogo = (brandName: string, iconType: string) => {
    const lower = brandName.toLowerCase();

    // Choose appropriate background color bubble
    const bgClass = 
      lower === 'slack' ? 'bg-[#4A154B]/20 text-[#E01E5A] border-[#E01E5A]/20' :
      lower === 'discord' ? 'bg-[#5865F2]/20 text-[#5865F2] border-[#5865F2]/20' :
      lower === 'jira' ? 'bg-[#0052CC]/20 text-[#0052CC] border-[#0052CC]/20' :
      lower === 'github' ? 'bg-white/10 text-white border-white/10' :
      lower === 'gitlab' ? 'bg-[#FC6D26]/20 text-[#FC6D26] border-[#FC6D26]/20' :
      lower === 'splunk' ? 'bg-[#000]/20 text-[#FF8800] border-[#FF8800]/20' :
      lower === 'thehive' ? 'bg-[#FFCC00]/20 text-[#FFCC00] border-[#FFCC00]/20' :
      lower === 'microsoft teams' || lower === 'teams' ? 'bg-[#6264A7]/20 text-[#6264A7] border-[#6264A7]/20' :
      lower === 'servicenow' ? 'bg-[#81B5A1]/20 text-[#81B5A1] border-[#81B5A1]/20' :
      lower === 'pagerduty' ? 'bg-[#00A86B]/20 text-[#00A86B] border-[#00A86B]/20' :
      lower === 'aws' || lower === 'aws s3' ? 'bg-[#FF9900]/20 text-[#FF9900] border-[#FF9900]/20' :
      'bg-cyber-blue/10 text-cyber-blue border-cyber-blue/20';

    if (lower === 'slack') {
      return (
        <div className={`p-2.5 rounded-sm border ${bgClass}`}>
